public class RandomCharacterArt {
    public static void main(String[] args) {
        int width = 10;
        int height = 5;
        char[][] art = generateArt(width, height);
        printArt(art);
    }

    public static char[][] generateArt(int width, int height) {
        char[][] art = new char[height][width];
        for (int i = 0; i < height; i++) {
            for (int j = 0; j < width; j++) {
                art[i][j] = getRandomCharacter();
            }
        }
        return art;
    }

    public static char getRandomCharacter() {
        // Generate a random character from 'A' to 'Z'
        return (char) ('A' + (int) (Math.random() * 26));
    }

    public static void printArt(char[][] art) {
        for (char[] row : art) {
            for (char c : row) {
                System.out.print(c + " ");
            }
            System.out.println();
        }
    }
}
