```javascript
function getRow(lst, x) {
    const coordinates = [];
    lst.forEach((row, rowIndex) => {
        row.forEach((value, colIndex) => {
            if (value === x) {
                coordinates.push([rowIndex, colIndex]);
            }
        });
    });

    // Sort by row index (ascending) and then by column index (descending)
    coordinates.sort((a, b) => {
        if (a[0] === b[0]) {
            return b[1] - a[1]; // Sort column index in descending order
        }
        return a[0] - b[0]; // Sort row index in ascending order
    });

    return coordinates;
}
